    "dash.maturityStage": { en: "Maturity Stage", hi: "परिपक्वता चरण", ta: "முதிர்வு நிலை", te: "పరిపక్వ దశ", kn: "ಪ್ರಬುದ್ಧ ಹಂತ", mr: "परिपक्वता टप्पा", pa: "ਪਰਿਪੱਕਤਾ ਪੜਾਅ", gu: "પરિપક્વતા તબક્કો" },
